  xpFill: TextureEntry;
  xpBorder: TextureEntry;
  buildFill: TextureEntry;
  buildBorder: TextureEntry;
  loadBg: TextureEntry;
  loadFill: TextureEntry;
  loadBorder: TextureEntry;
  loadGlass: TextureEntry;
  glueBg: TextureEntry;
